// Daisy Flower — a cheerful, parametric flower
// --------------------------------------------
// A domed central disc, N petals fanned radially around it, a tapering stem,
// and a pair of leaves. Built manifold-js native: every region is wrapped in
// api.label(...) *before* the unions so it can be painted by name afterwards
// (labels ride through .add()/union via manifold-3d's runOriginalID provenance).
//
// Knobs (api.params) drive the Customizer panel; defaults are tuned to look
// great as a catalog tile. The whole flower fuses into ONE connected solid —
// petals overlap the disc, the disc sinks into the stem top, and each leaf
// sinks into the stem — verified at the end with api.expectUnion.

const { Manifold, CrossSection } = api;

const p = api.params({
  petalCount: { type: 'int', default: 12, min: 5, max: 24,
                label: 'Petal count', help: 'How many petals fan around the center.' },
  petalShape: { type: 'select', default: 'rounded',
                options: [
                  { value: 'rounded', label: 'Rounded' },
                  { value: 'pointed', label: 'Pointed' },
                  { value: 'spoon',   label: 'Spoon' },
                ],
                label: 'Petal shape', help: 'Silhouette of each petal tip.' },
  petalLength: { type: 'number', default: 26, min: 12, max: 50, step: 1, unit: 'mm',
                 label: 'Petal length' },
  centerDiameter: { type: 'number', default: 22, min: 10, max: 40, step: 1, unit: 'mm',
                    label: 'Center diameter', help: 'The domed disc the petals attach to.' },
  centerDome: { type: 'number', default: 6, min: 1, max: 16, step: 0.5, unit: 'mm',
                label: 'Center dome height' },
  stemHeight: { type: 'number', default: 55, min: 20, max: 110, step: 1, unit: 'mm',
                label: 'Stem height' },
  stemThickness: { type: 'number', default: 4, min: 2, max: 10, step: 0.5, unit: 'mm',
                   label: 'Stem thickness' },
  leaves: { type: 'boolean', default: true, label: 'Show leaves' },
});

// ----------------------------------------------------------------------------
// Derived dimensions
// ----------------------------------------------------------------------------
const rCenter = p.centerDiameter / 2;
const stemR = p.stemThickness / 2;
const headZ = p.stemHeight;          // flower head sits at the top of the stem
const overlap = 1.2;                 // generous (>0.5) volumetric overlap for clean fusion

// ----------------------------------------------------------------------------
// STEM — a gently tapering cylinder, a touch fatter at the base so it "plants"
// itself. Base at z=0, top reaches up into the flower head.
// ----------------------------------------------------------------------------
const stem = api.label(
  Manifold.cylinder(headZ + overlap, stemR * 1.35, stemR),
  'stem',
);

// ----------------------------------------------------------------------------
// CENTER — a low disc capped by a squashed half-sphere, giving a soft pollen
// dome. The disc base is sunk by `overlap` so it fuses with the stem top.
// ----------------------------------------------------------------------------
const discH = Math.max(2, p.centerDome * 0.5);
const disc = Manifold.cylinder(discH, rCenter, rCenter)
  .translate([0, 0, headZ - overlap]);

// Dome: a unit sphere scaled to (rCenter, rCenter, centerDome) then trimmed to
// its top half, seated on the disc so the two overlap.
const dome = Manifold.sphere(1)
  .scale([rCenter, rCenter, p.centerDome])
  .trimByPlane([0, 0, 1], 0)                       // keep the upper hemisphere
  .translate([0, 0, headZ - overlap + discH - 0.4]); // seat on disc (slight overlap)

const center = api.label(disc.add(dome), 'center');

// ----------------------------------------------------------------------------
// PETAL — one prototype lying along +X, centered in Z on the disc's mid-plane.
// circularPattern's `radius` shortcut pushes it out along +X then fans N copies
// around Z, so the inner end overlaps the disc and the petal points outward.
//
// A petal is an extruded 2D silhouette (in XY), thin in Z, with a slight upward
// tilt at the tip so the bloom looks alive rather than flat.
// ----------------------------------------------------------------------------
const petalLen = p.petalLength;
const petalThick = Math.max(1.6, p.centerDome * 0.45); // thickness in Z
const halfW = petalLen * 0.30;                          // max half-width of the petal

// Silhouette walked CCW in the XY plane: root near x=0, tip at x=petalLen.
// Different `petalShape` values reshape the tip + waist.
let outline;
if (p.petalShape === 'pointed') {
  outline = [
    [0, 0],
    [petalLen * 0.35, -halfW * 0.85],
    [petalLen * 0.78, -halfW * 0.55],
    [petalLen, 0],                       // sharp tip
    [petalLen * 0.78, halfW * 0.55],
    [petalLen * 0.35, halfW * 0.85],
  ];
} else if (p.petalShape === 'spoon') {
  // Pinched waist, wide rounded paddle at the tip.
  outline = [
    [0, 0],
    [petalLen * 0.30, -halfW * 0.45],
    [petalLen * 0.62, -halfW * 0.95],
    [petalLen * 0.92, -halfW * 0.80],
    [petalLen, 0],
    [petalLen * 0.92, halfW * 0.80],
    [petalLen * 0.62, halfW * 0.95],
    [petalLen * 0.30, halfW * 0.45],
  ];
} else {
  // 'rounded' (default) — classic daisy teardrop, fullest about 2/3 out.
  outline = [
    [0, 0],
    [petalLen * 0.28, -halfW * 0.70],
    [petalLen * 0.62, -halfW * 1.00],
    [petalLen * 0.86, -halfW * 0.78],
    [petalLen, 0],
    [petalLen * 0.86, halfW * 0.78],
    [petalLen * 0.62, halfW * 1.00],
    [petalLen * 0.28, halfW * 0.70],
  ];
}

const petalProto = CrossSection.ofPolygons([outline])
  .extrude(petalThick)
  .translate([0, 0, -petalThick / 2])      // center the slab in Z
  .rotate([0, -8, 0])                       // lift the tip slightly for a lively bloom
  // Pull the root inward so it dives into the disc; the radius push then places
  // the overlap zone right at the disc rim.
  .translate([rCenter * 0.45, 0, headZ - overlap + discH * 0.5]);

// Fan the petals. radius pushes the (already partly-inset) petal outward so its
// inner end overlaps the center disc — guaranteeing they fuse into the disc.
const petals = api.label(
  api.circularPattern(petalProto, p.petalCount, { radius: 0, axis: 'z' }),
  'petals',
);

// ----------------------------------------------------------------------------
// LEAVES — two flat lens-shaped blades branching off the stem, mid-height,
// pointing out along ±X with an upward lift. Built once, then mirror-copied.
// Each leaf sinks into the stem so it fuses.
// ----------------------------------------------------------------------------
function buildLeaves() {
  const leafLen = Math.min(petalLen * 1.05, p.stemHeight * 0.5);
  const leafW = leafLen * 0.42;
  const leafThick = Math.max(1.4, petalThick * 0.8);

  // Pointed-oval blade in XY (a leaf shape), walked CCW, root at x=0.
  const leafOutline = [
    [0, 0],
    [leafLen * 0.30, -leafW * 0.5],
    [leafLen * 0.70, -leafW * 0.42],
    [leafLen, 0],
    [leafLen * 0.70, leafW * 0.42],
    [leafLen * 0.30, leafW * 0.5],
  ];

  const blade = CrossSection.ofPolygons([leafOutline])
    .extrude(leafThick)
    .translate([0, 0, -leafThick / 2])
    .rotate([0, -22, 0])               // tilt the blade upward
    // Root sits inside the stem so it fuses; placed about 45% up the stem.
    .translate([stemR - 0.6, 0, p.stemHeight * 0.45]);

  // Right leaf as-is; left leaf mirrored across X so they oppose each other.
  const right = blade.rotate([0, 0, 18]);
  const left = blade.rotate([0, 0, 180 - 18]);
  return api.label(right.add(left), 'leaves');
}

// ----------------------------------------------------------------------------
// ASSEMBLE — union everything; verify it's a single connected solid.
// ----------------------------------------------------------------------------
const parts = [stem, center, petals];
if (p.leaves) parts.push(buildLeaves());

return api.expectUnion(parts, { expectComponents: 1 });

